    75→    emit(3.0);
    76→    emit(3.5);
    77→    emit(5.0);
    78→    emit(7.5);
    79→    emit(-1.5);
    80→    emit(-3.5);
    81→    emit(-5.0);
    82→}
    83→
    84→/* 5. Common values */
    85→static void test_common(void)
    86→{
    87→    double vals[] = { 2.5, 3.14159, 10.0, 100.0, 1000.0 };
    88→    int n = sizeof(vals) / sizeof(vals[0]);
    89→    for (int i = 0; i < n; i++) {
    90→        emit(vals[i]);
    91→        emit(-vals[i]);
    92→    }
    93→}
    94→
    95→/* 6. Large values */
    96→static void test_large(void)
    97→{
    98→    emit(1.0e100);
    99→    emit(-1.0e100);
   100→    emit(1.0e200);
   101→    emit(-1.0e200);
   102→    emit(DBL_MAX);
   103→    emit(-DBL_MAX);
   104→}
   105→
   106→/* 7. Sweep across multiple octaves */
   107→static void test_sweep(void)
   108→{
   109→    double bases[] = { 1.0, 1.5, 2.5, 3.5, 5.0, 7.5 };
   110→    int nbases = sizeof(bases) / sizeof(bases[0]);
   111→    for (int p = -10; p <= 10; p += 2) {
   112→        double scale = (1 << (p / 2));
   113→        if (p & 1) scale *= 1.414213562373095;  /* sqrt(2) */
   114→        for (int i = 0; i < nbases; i++) {
   115→            emit(bases[i] * scale);
   116→        }
   117→    }
   118→}
