    61→    emit_u(0x3ff0000000000000ULL); /* 1.0 exactly */
    62→    emit_u(0x3ff0000000000001ULL); /* 1.0 + eps */
    63→    emit(1.0 + 1.0e-150);
    64→    emit(1.0 + 1.0e-50);
    65→}
    66→
