   144→{
   145→    uint64_t start = 0x3ff0000000000000ULL; /* 1.0 */
   146→    uint64_t end = 0x4000000000000000ULL;   /* 2.0 */
   147→
   148→    for (uint64_t b = start; b <= end; b += 4194304)
   149→        emit_u(b);
   150→}
   151→
   152→/* ------------------------------------------------------------------ */
   153→
   154→int main(void)
   155→{
