    52→    emit(-0.0, 0.5);
    53→    emit(0.0, 2.0);
    54→
    55→    /* Base = 1 (identity) */
    56→    emit(1.0, 0.0);
    57→    emit(1.0, 2.0);
    58→    emit(1.0, -2.0);
    59→    emit(1.0, 100.0);
