    68→    emit_u(0x3ff0000000000000ULL, 0x7ff8000000000000ULL); /* qNaN exp */
    69→    emit_u(0x7ff0000000000000ULL, 0x3ff0000000000000ULL); /* +Inf base */
    70→    emit_u(0xfff0000000000000ULL, 0x3ff0000000000000ULL); /* -Inf base */
    71→}
    72→
    73→/* 2. Tiny values */
    74→static void test_tiny(void)
    75→{
    76→    /* Small bases with small exponents */
    77→    emit_u(0x0000000000000001ULL, 0x3ff0000000000000ULL); /* min denorm, exp=1 */
    78→    emit(1.0e-150, 2.0);
    79→    emit(1.0e-150, 0.5);
    80→    emit(1.0e-50, 10.0);
