    89→/* 3. Known mathematical values (Pythagorean relations) */
    90→static void test_known(void)
    91→{
    92→    /* Base and exponent pairs: (3,2)=9, (4,2)=16, (5,2)=25 (3-4-5 triple squared) */
    93→    emit(3.0, 2.0);   /* 9 */
    94→    emit(4.0, 2.0);   /* 16 */
    95→    emit(5.0, 2.0);   /* 25 (sqrt(9+16)) */
    96→
    97→    /* Base and exponent pairs: (5,2)=25, (12,2)=144, (13,2)=169 (5-12-13 triple squared) */
    98→    emit(5.0, 2.0);   /* 25 */
    99→    emit(12.0, 2.0);  /* 144 */
   100→    emit(13.0, 2.0);  /* 169 */
