   103→    emit(2.0, 1.0);
   104→    emit(2.0, 2.0);
   105→    emit(2.0, 3.0);
   106→    emit(2.0, 4.0);
   107→    emit(2.0, 8.0);
   108→    emit(2.0, 10.0);
   109→    emit(2.0, -1.0);
   110→    emit(2.0, -2.0);
   111→
   112→    /* Powers of 10 */
   113→    emit(10.0, 1.0);
   114→    emit(10.0, 2.0);
   115→    emit(10.0, 3.0);
   116→    emit(10.0, -1.0);
   117→    emit(10.0, -2.0);
   118→
   119→    /* Fractional exponents */
   120→    emit(4.0, 0.5);    /* sqrt(4) = 2 */
   121→    emit(8.0, 0.333333);  /* cbrt(8) ~ 2 */
   122→    emit(16.0, 0.25);  /* 16^(1/4) = 2 */
   123→}
   124→
   125→/* 4. Large arguments */
   126→static void test_large(void)
   127→{
   128→    double base_vals[] = {
   129→        1.0e10, 1.0e100, DBL_MAX,
   130→        2.0, 10.0, 100.0,
   131→        -2.0, -10.0,
   132→    };
   133→
   134→    int nbases = sizeof(base_vals) / sizeof(base_vals[0]);
   135→    for (int i = 0; i < nbases; i++) {
   136→        emit(base_vals[i], 2.0);
   137→        emit(base_vals[i], 0.5);
   138→        emit(base_vals[i], -1.0);
   139→    }
   140→}
