   142→/* 5. Exponent magnitude sensitivity */
   143→static void test_exponent_range(void)
   144→{
   145→    /* Base 2 with various exponents */
   146→    double exps[] = { -100.0, -10.0, -1.0, -0.5, 0.0, 0.5, 1.0, 10.0, 100.0 };
   147→    int nexps = sizeof(exps) / sizeof(exps[0]);
   148→
   149→    for (int i = 0; i < nexps; i++) {
   150→        emit(2.0, exps[i]);
   151→        emit(0.5, exps[i]);
   152→        emit(10.0, exps[i]);
   153→    }
   154→}
   155→
   156→/* 6. Worst-case rounding */
   157→static void test_hard(void)
   158→{
   159→    double cases[][2] = {
   160→        { 2.0, 2.0 },
   161→        { 2.0, 3.0 },
   162→        { 3.0, 2.0 },
   163→        { 3.0, 3.0 },
   164→        { 1.5, 4.0 },
   165→        { 1.5, -4.0 },
   166→        { u2d(0x3ff0000000000000ULL), u2d(0x4000000000000000ULL) }, /* 1.0, 2.0 */
   167→        { u2d(0x4000000000000000ULL), u2d(0x4000000000000000ULL) }, /* 2.0, 2.0 */
   168→    };
   169→    int n = sizeof(cases) / sizeof(cases[0]);
   170→    for (int i = 0; i < n; i++) {
   171→        emit(cases[i][0], cases[i][1]);
   172→        emit(-cases[i][0], cases[i][1]);
   173→    }
   174→}
   175→
   176→/* 7. Sweep base [0.5, 10] and exponent [0, 5] */
   177→static void test_sweep(void)
   178→{
   179→    int nbase = 50;
   180→    int nexp = 50;
   181→
   182→    for (int i = 0; i <= nbase; i++) {
   183→        double base = 0.5 + (10.0 - 0.5) * (double)i / (double)nbase;
   184→        for (int j = 0; j <= nexp; j++) {
   185→            double exp = (double)j * 5.0 / (double)nexp;
   186→            emit(base, exp);
   187→        }
   188→    }
   189→}
   190→
   191→/* 8. Sample critical range with ULP granularity */
   192→static void test_exhaustive_small(void)
   193→{
   194→    /* Base in [1.0, 2.0], exponent in [0, 1] */
   195→    uint64_t base_start = 0x3ff0000000000000ULL; /* 1.0 */
   196→    uint64_t base_end = 0x4000000000000000ULL;   /* 2.0 */
   197→    uint64_t exp_start = 0x0000000000000000ULL;  /* 0.0 */
   198→    uint64_t exp_end = 0x3ff0000000000000ULL;    /* 1.0 */
   199→
   200→    for (uint64_t b = base_start; b <= base_end; b += 17179869)
   201→        for (uint64_t e = exp_start; e <= exp_end; e += 17179869)
   202→            emit_u(b, e);
   203→}
   204→
   205→/* ------------------------------------------------------------------ */
   206→
   207→int main(void)
   208→{
   209→    test_special();
   210→    test_tiny();
   211→    test_known();
   212→    test_large();
   213→    test_exponent_range();
   214→    test_hard();
   215→    test_sweep();
   216→    test_exhaustive_small();
   217→    return 0;
   218→}
