     1→/*
     2→ * log1p() test harness — prints (input_hex, output_hex) pairs.
     3→ *
     4→ * Build two versions:
     5→ *   1. Linked with optimized Andes assembly log1p   (test_log1p_opt.elf)
     6→ *   2. Linked with toolchain's default log1p        (test_log1p_ref.elf)
     7→ * Run both, diff the output to find discrepancies.
     8→ */
     9→
    10→#include <math.h>
    11→#include <stdint.h>
    12→#include <stdio.h>
    13→#include <float.h>
    14→
    15→static inline uint64_t d2u(double d)
    16→{
    17→    union { double d; uint64_t u; } x;
    18→    x.d = d;
    19→    return x.u;
    20→}
    21→
    22→static inline double u2d(uint64_t u)
    23→{
    24→    union { double d; uint64_t u; } x;
    25→    x.u = u;
    26→    return x.d;
    27→}
    28→
    29→static void emit(double x)
    30→{
    31→    double r = log1p(x);
    32→    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
    33→}
    34→
    35→static void emit_u(uint64_t bits)
    36→{
    37→    emit(u2d(bits));
    38→}
    39→
    40→/* ------------------------------------------------------------------ */
    41→/* Test points                                                         */
    42→/* ------------------------------------------------------------------ */
    43→
    44→/* 1. Special values */
    45→static void test_special(void)
    46→{
    47→    /* Zeros (log1p(0) = 0) */
    48→    emit(0.0);
    49→    emit(-0.0);
    50→
    51→    /* NaN */
    52→    emit_u(0x7ff8000000000000ULL); /* qNaN */
    53→    emit_u(0x7ff0000000000001ULL); /* sNaN */
    54→    emit_u(0xfff8000000000000ULL); /* -NaN */
    55→
    56→    /* Infinity */
    57→    emit_u(0x7ff0000000000000ULL); /* +Inf (log1p(Inf) = Inf) */
    58→    emit_u(0xfff0000000000000ULL); /* -Inf (log1p(-Inf) = NaN) */
    59→
    60→    /* Boundary: log1p(-1) = -Inf */
    61→    emit_u(0xbff0000000000000ULL); /* -1.0 */
    62→}
    63→
    64→/* 2. Tiny values: log1p(x) ~ x when x is tiny */
    65→static void test_tiny(void)
    66→{
    67→    emit_u(0x0000000000000001ULL); /* min denorm */
    68→    emit_u(0x8000000000000001ULL);
    69→    emit_u(0x0008000000000000ULL); /* mid denorm */
    70→    emit_u(0x8008000000000000ULL);
    71→    emit_u(0x000fffffffffffffULL); /* max denorm */
    72→    emit_u(0x800fffffffffffffULL);
    73→    emit(DBL_MIN);
    74→    emit(-DBL_MIN);
    75→    emit(1.0e-200);
    76→    emit(-1.0e-200);
    77→    emit(1.0e-100);
    78→    emit(-1.0e-100);
    79→}
    80→
    81→/* 3. Known mathematical values */
    82→static void test_known(void)
    83→{
    84→    emit(0.0);                      /* log1p(0) = 0 */
    85→    emit(1.0);                      /* log1p(1) = log(2) */
    86→    emit(2.718281828 - 1.0);        /* log1p(e-1) = 1 */
    87→    emit(-0.5);                     /* log1p(-0.5) = log(0.5) */
    88→    emit(0.5);                      /* log1p(0.5) = log(1.5) */
    89→    emit(9.0);                      /* log1p(9) = log(10) */
    90→    emit(-0.9);                     /* log1p(-0.9) = log(0.1) */
    91→    emit(99.0);                     /* log1p(99) = log(100) */
    92→}
    93→
    94→/* 4. Large values */
    95→static void test_large(void)
    96→{
    97→    double vals[] = {
    98→        10.0, 100.0, 1000.0, 10000.0, 100000.0,
    99→        1.0e50, 1.0e100, 1.0e150, 1.0e200, 1.0e300,
   100→        DBL_MAX,
   101→        -0.5, -0.9, -0.99, -0.999, -0.9999, -0.99999,
   102→    };
   103→    int n = sizeof(vals) / sizeof(vals[0]);
   104→    for (int i = 0; i < n; i++)
   105→        emit(vals[i]);
   106→}
   107→
   108→/* 5. Critical near-zero region where log1p(x) ~ x */
   109→static void test_quadrant(void)
   110→{
   111→    double tiny_vals[] = {
   112→        1.0e-20, 5.0e-20, 1.0e-15, 5.0e-15,
   113→        1.0e-10, 5.0e-10, 1.0e-5, 5.0e-5,
   114→        1.0e-3, 1.0e-2,
   115→        -1.0e-20, -5.0e-20, -1.0e-15, -5.0e-15,
   116→        -1.0e-10, -5.0e-10, -1.0e-5, -5.0e-5,
   117→        -1.0e-3, -1.0e-2,
   118→    };
   119→    int n = sizeof(tiny_vals) / sizeof(tiny_vals[0]);
   120→    for (int i = 0; i < n; i++)
   121→        emit(tiny_vals[i]);
   122→}
   123→
   124→/* 6. Worst-case near boundaries */
   125→static void test_hard(void)
   126→{
   127→    double cases[] = {
   128→        u2d(0x3ff0000000000000ULL), /* 1.0 exactly (log1p(1) = log(2)) */
   129→        u2d(0x3ff0000000000001ULL), /* 1.0 + 1 ULP */
   130→        u2d(0x3feffffffffffffULL), /* 1.0 - 1 ULP */
   131→        u2d(0xbff0000000000000ULL), /* -1.0 exactly (log1p(-1) = -Inf) */
   132→        u2d(0xbfeffffffffffffULL), /* -1.0 + 1 ULP */
   133→        u2d(0xbff0000000000001ULL), /* -1.0 - 1 ULP */
   134→        -0.999999, -0.99999, -0.9999,
   135→        0.999999, 0.99999, 0.9999,
   136→    };
   137→    int n = sizeof(cases) / sizeof(cases[0]);
   138→    for (int i = 0; i < n; i++)
   139→        emit(cases[i]);
   140→}
   141→
   142→/* 7. Sweep [-0.95, 100.0] in 200 steps */
   143→static void test_sweep(void)
   144→{
   145→    double lo = -0.95;
   146→    double hi = 100.0;
   147→    int nsteps = 200;
   148→    double step = (hi - lo) / (double)nsteps;
   149→
   150→    /* [-0.95, 100.0] */
   151→    for (int i = 0; i <= nsteps; i++)
   152→        emit(lo + (double)i * step);
   153→
   154→    /* [100.0, -0.95] (decreasing) */
   155→    for (int i = 0; i <= nsteps; i++)
   156→        emit(hi - (double)i * step);
   157→}
   158→
   159→/* 8. Sample [0, 0.1] every 2^47 ULP (~256 cases) */
   160→static void test_exhaustive_small(void)
   161→{
   162→    uint64_t end = 0x3fb999999999999aULL; /* ~0.1 */
   163→    for (uint64_t b = 0; b <= end; b += (1ULL << 47))
   164→        emit_u(b);
   165→}
   166→
   167→/* ------------------------------------------------------------------ */
   168→
   169→int main(void)
   170→{
   171→    test_special();
   172→    test_tiny();
   173→    test_known();
   174→    test_large();
   175→    test_quadrant();
   176→    test_hard();
   177→    test_sweep();
   178→    test_exhaustive_small();
   179→    return 0;
   180→}
